function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    const pq = new PriorityQueue<[number, number, number, number]>([(0, 0, 0, 0)]); // [cost, row, col, usedK]

    while (!pq.isEmpty()) {
        const [cost, row, col, usedK] = pq.poll();

        if (row === m - 1 && col === n - 1) {
            return cost;
        }

        if (usedK >= k) {
            // Only use normal moves
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;
                if (newRow < m && newCol < n) {
                    const newCost = cost + grid[newRow][newCol];
                    if (newCost < dist[newRow][newCol]) {
                        dist[newRow][newCol] = newCost;
                        pq.offer([newCost, newRow, newCol, usedK]);
                    }
                }
            }
        } else {
            // Try normal move
            for (const [dr, dc] of dirs) {
                const newRow = row + dr;
                const newCol = col + dc;
                if (newRow < m && newCol < n) {
                    const newCost = cost + grid[newRow][newCol];
                    if (newCost < dist[newRow][newCol]) {
                        dist[newRow][newCol] = newCost;
                        pq.offer([newCost, newRow, newCol, usedK + 1]);
                    }
                }
            }

            // Try teleport
            for (let i = 0; i < m; i++) {
                for (let j = 0; j < n; j++) {
                    if (grid[i][j] <= grid[row][col]) {
                        if (dist[i][j] > cost) {
                            dist[i][j] = cost;
                            pq.offer([cost, i, j, usedK + 1]);
                        }
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue<T> {
    private heap: T[];
    private comparator: (a: T, b: T) => number;

    constructor(private initial: T[]) {
        this.heap = initial;
        this.comparator = (a, b) => {
            if (a === b) return 0;
            return a[0] - b[0];
        };
        this.buildHeap();
    }

    private buildHeap() {
        for (let i = Math.floor(this.heap.length / 2) - 1; i >= 0; i--) {
            this.heapify(i);
        }
    }

    private heapify(i: number) {
        let smallest = i;
        const left = 2 * i + 1;
        const right = 2 * i + 2;

        if (left < this.heap.length && this.comparator(this.heap[left], this.heap[smallest]) < 0) {
            smallest = left;
        }

        if (right < this.heap.length && this.comparator(this.heap[right], this.heap[smallest]) < 0) {
            smallest = right;
        }

        if (smallest !== i) {
            [this.heap[i], this.heap[smallest]] = [this.heap[smallest], this.heap[i]];
            this.heapify(smallest);
        }
    }

    public isEmpty(): boolean {
        return this.heap.length === 0;
    }

    public poll(): T {
        if (this.isEmpty()) return undefined;
        const popped = this.heap[0];
        this.heap[0] = this.heap[this.heap.length - 1];
        this.heap.pop();
        this.heapify(0);
        return popped;
    }

    public offer(value: T): void {
        this.heap.push(value);
        this.heapify(this.heap.length - 1);
    }
}

